class Solution(object):
    def findMaxVal(self, n, restrictions, diff):
        # Compute prefix sums of diff for max reachable value from position 0
        # prefix_diff[i] = sum(diff[0..i-1]) = max value reachable at position i from 0
        prefix_diff = [0] * n
        for i in range(1, n):
            prefix_diff[i] = prefix_diff[i-1] + diff[i-1]

        # Upper bound at each position: starts as prefix_diff[i]
        upper = list(prefix_diff)

        # Apply restrictions
        for idx, maxVal in restrictions:
            upper[idx] = min(upper[idx], maxVal)

        # Propagate constraints left-to-right and right-to-left
        # Left to right: upper[i] <= upper[i-1] + diff[i-1]
        for i in range(1, n):
            upper[i] = min(upper[i], upper[i-1] + diff[i-1])

        # Right to left: upper[i] <= upper[i+1] + diff[i]
        for i in range(n-2, -1, -1):
            upper[i] = min(upper[i], upper[i+1] + diff[i])

        return max(upper)
